class Counter extends React.Component {
  constructor(props) {
    super(props); // must be first
    this.state = { count: props.initialCount ?? 0 };
    this.increment = this.increment.bind(this);
  }

  increment() {
    this.setState(prev => ({ count: prev.count + 1 }));
  }

  render() {
    return <button onClick={this.increment}>{this.state.count}</button>;
  }
}

class ControlledInput extends React.Component {
  static getDerivedStateFromProps(props, state) {
    if (props.value !== state.prevPropsValue) {
      return { value: props.value, prevPropsValue: props.value };
    }
    return null;
  }

  state = { value: this.props.value, prevPropsValue: this.props.value };

  render() {
    return (
      <input
        value={this.state.value}
        onChange={e => this.setState({ value: e.target.value })}
      />
    );
  }
}

class ItemList extends React.Component {
  render() {
    const { items, emptyMessage } = this.props;
    if (!items.length) return <p>{emptyMessage}</p>;
    return (
      <ul>
        {items.map(item => (
          <li key={item.id}>{item.name}</li>
        ))}
      </ul>
    );
  }
}

class UserProfile extends React.Component {
  state = { user: null, loading: true, error: null };

  async componentDidMount() {
    try {
      const res = await fetch(`/api/users/${this.props.userId}`);
      if (!res.ok) throw new Error(res.statusText);
      const user = await res.json();
      this.setState({ user, loading: false });
    } catch (error) {
      this.setState({ error: error.message, loading: false });
    }
  }

  render() {
    const { user, loading, error } = this.state;
    if (loading) return <p>Loading…</p>;
    if (error) return <p>Error: {error}</p>;
    return <h1>{user.name}</h1>;
  }
}

class ExpensiveChart extends React.Component {
  shouldComponentUpdate(nextProps) {
    return nextProps.data !== this.props.data;
  }
  render() {
    return <canvas ref={this.canvasRef} />;
  }
}

// Or: extend PureComponent for automatic shallow comparison
class ExpensiveChart extends React.PureComponent {
  render() {
    return <canvas ref={this.canvasRef} />;
  }
}

class ChatThread extends React.Component {
  containerRef = React.createRef();

  getSnapshotBeforeUpdate(prevProps) {
    if (prevProps.messages.length < this.props.messages.length) {
      const container = this.containerRef.current;
      return container.scrollHeight - container.scrollTop;
    }
    return null;
  }

  componentDidUpdate(prevProps, prevState, snapshot) {
    if (snapshot !== null) {
      const container = this.containerRef.current;
      container.scrollTop = container.scrollHeight - snapshot;
    }
  }

  render() {
    return (
      <div ref={this.containerRef} style={{ overflowY: 'auto', height: 400 }}>
        {this.props.messages.map(m => <p key={m.id}>{m.text}</p>)}
      </div>
    );
  }
}

class ArticleViewer extends React.Component {
  state = { article: null };

  async componentDidUpdate(prevProps) {
    if (prevProps.slug !== this.props.slug) {
      const res = await fetch(`/api/articles/${this.props.slug}`);
      const article = await res.json();
      this.setState({ article });
    }
  }

  render() {
    return <article>{this.state.article?.body}</article>;
  }
}

class StoreSubscriber extends React.Component {
  componentDidMount() {
    this.unsubscribe = store.subscribe(this.handleChange);
    this.timerId = setInterval(this.poll, 10_000);
    document.addEventListener('visibilitychange', this.handleVisibility);
  }

  componentWillUnmount() {
    this.unsubscribe();
    clearInterval(this.timerId);
    document.removeEventListener('visibilitychange', this.handleVisibility);
  }

  handleChange = () => this.setState({ data: store.getData() });
  handleVisibility = () => {};
  poll = () => {};

  render() { return null; }
}

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, errorMessage: null };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, errorMessage: error.message };
  }

  componentDidCatch(error, info) {
    reportError(error, info.componentStack);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div role="alert">
          <h2>Something went wrong.</h2>
          <details>{this.state.errorMessage}</details>
        </div>
      );
    }
    return this.props.children;
  }
}

// Bug: mutation skips PureComponent re-render
class BadList extends React.PureComponent {
  addItem(item) {
    this.state.items.push(item); // mutates in place — reference unchanged
    this.setState({ items: this.state.items }); // no re-render!
  }
}

// Fix: always produce a new reference
class GoodList extends React.PureComponent {
  addItem(item) {
    this.setState(prev => ({ items: [...prev.items, item] }));
  }
}

class VideoPlayer extends React.Component {
  constructor(props) {
    super(props);
    this.videoRef = React.createRef();
  }

  play() {
    this.videoRef.current.play();
  }

  setCanvasRef = element => {
    this.canvas = element;
    if (element) {
      this.ctx = element.getContext('2d');
    }
  };

  render() {
    return (
      <>
        <video ref={this.videoRef} src={this.props.src} />
        <canvas ref={this.setCanvasRef} />
      </>
    );
  }
}

const ThemeContext = React.createContext('light');

// Single context via contextType
class ThemedButton extends React.Component {
  static contextType = ThemeContext;

  render() {
    const theme = this.context;
    return <button className={`btn-${theme}`}>{this.props.children}</button>;
  }
}

// Multiple contexts via render props
class MultiContextComponent extends React.Component {
  render() {
    return (
      <ThemeContext.Consumer>
        {theme => (
          <UserContext.Consumer>
            {user => <div className={theme}>Welcome, {user.name}</div>}
          </UserContext.Consumer>
        )}
      </ThemeContext.Consumer>
    );
  }
}
